          <p style={s.lead}>Real outcomes from real users — tracked, verified, and growing every day.</p>
        </div>
        <div style={s2.statsGrid}>
          {STATS.map(stat => <StatItem key={stat.label} stat={stat} active={active} />)}
        </div>
      </div>
    </section>
  );
}

